func (e *emitter) buildRecvTypes(d *ast.FuncDecl) map[string]string {
	out := map[string]string{}
	add := func(fl *ast.FieldList) {
		if fl == nil {
			return
		}
		for _, f := range fl.List {
			base := recvBaseType(f.Type)
			if base == "" {
				continue
			}
			for _, n := range f.Names {
				if n != nil && n.Name != "" && n.Name != "_" {
					out[n.Name] = base
				}
			}
		}
	}
	add(d.Recv)
	if d.Type != nil {
		add(d.Type.Params)
	}
	if len(out) == 0 {
		return nil
	}
	return out
}

